  ? normalizeMatrixAllowList(params.allowFrom)  // Room: config only
  : effectiveAllowFrom;  // DM: include pairing store

const commandAllowMatch = params.isRoom
  ? resolveMatrixAllowListMatch({
      allowList: normalizeMatrixAllowList(params.allowFrom),
      userId: params.senderId,
    })
  : directAllowMatch;

return {
  // ...
  commandAuthorizers: [
    {
      configured: commandAllowFrom.length > 0,
      allowed: commandAllowMatch.allowed,
    },
    // ...
  ],
};
```

**Option 2: Use core's resolveDmGroupAccessWithCommandGate**
```typescript
// In handler.ts or access-state.ts
import { resolveDmGroupAccessWithCommandGate } from "openclaw/plugin-sdk/security-runtime";

const result = resolveDmGroupAccessWithCommandGate({
  isGroup: isRoom,
  dmPolicy,
  groupPolicy,
  allowFrom,
  groupAllowFrom,
  storeAllowFrom,  // Core handles the boundary
  isSenderAllowed: (list) => resolveMatrixAllowListMatches({...}),
  command: {
    useAccessGroups,
    allowTextCommands,
    hasControlCommand,
  },
